package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import java.util.Optional;

import org.eclipse.rdf4j.common.annotation.Experimental;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.leo.LeoEvidence;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.leo.LeoMemoFeedback;

/**
 * Conservative reconciliation between base/OMNI estimates and learned LEO evidence.
 */
@Experimental
final class LeoEstimateReconciler {

	private LeoEstimateReconciler() {
	}

	static Optional<LeoEvidence> choose(TupleExpr tupleExpr, StatisticsEstimate base, LeoMemoFeedback feedback) {
		if (tupleExpr == null || base == null || feedback == null || feedback.isEmpty()) {
			return Optional.empty();
		}
		Optional<LeoEvidence> best = feedback.bestEvidence()
				.filter(evidence -> Double.isFinite(evidence.rows()) && evidence.rows() >= 0.0d);
		if (best.isEmpty()) {
			stamp(tupleExpr, "none", "no-finite-learned-evidence", Double.NaN, Double.NaN, Double.NaN);
			return Optional.empty();
		}
		LeoEvidence evidence = best.get();
		if (evidence.protectedEstimate()) {
			stamp(tupleExpr, "use-leo", "learned-evidence-is-protected", ratio(evidence.rows(), base.rows()),
					ratio(evidence.workRows(), base.workRows()), evidence.confidence());
			return best;
		}
		if (protectedBase(base, evidence)) {
			stamp(tupleExpr, "keep-base", "base-or-omni-evidence-is-more-specific", ratio(evidence.rows(), base.rows()),
					ratio(evidence.workRows(), base.workRows()), evidence.confidence());
			return Optional.empty();
		}
		if (staleOrThinScalar(evidence)) {
			stamp(tupleExpr, "keep-base", "scalar-feedback-is-too-thin-or-low-confidence",
					ratio(evidence.rows(), base.rows()), ratio(evidence.workRows(), base.workRows()),
					evidence.confidence());
			return Optional.empty();
		}
		stamp(tupleExpr, "use-leo", "learned-evidence-is-calibrated", ratio(evidence.rows(), base.rows()),
				ratio(evidence.workRows(), base.workRows()), evidence.confidence());
		return best;
	}

	private static boolean protectedBase(StatisticsEstimate base, LeoEvidence evidence) {
		String method = base.method() == null ? "" : base.method().toLowerCase(java.util.Locale.ROOT);
		boolean baseLooksExact = method.contains("exact") || method.contains("finite");
		boolean baseLooksOmni = method.contains("omni") || method.contains("sketch");
		double baseConfidence = base.qErrorInterval() == null ? 0.0d : base.qErrorInterval().confidence();
		if (baseLooksExact && evidence.kind() != LeoEvidence.Kind.EXACT_FINITE_RELATION) {
			return true;
		}
		return baseLooksOmni
				&& evidence.kind() == LeoEvidence.Kind.SCALAR_OPERATOR_FEEDBACK
				&& baseConfidence >= 0.80d
				&& evidence.confidence() < 0.88d;
	}

	private static boolean staleOrThinScalar(LeoEvidence evidence) {
		return evidence.kind() == LeoEvidence.Kind.SCALAR_OPERATOR_FEEDBACK
				&& (evidence.evidenceCount() < 2L || evidence.confidence() < 0.05d);
	}

	private static double ratio(double learned, double base) {
		if (!Double.isFinite(learned) || learned < 0.0d || !Double.isFinite(base) || base <= 0.0d) {
			return Double.NaN;
		}
		return learned / base;
	}

	private static void stamp(TupleExpr tupleExpr, String decision, String reason, double rowRatio, double workRatio,
			double confidence) {
		tupleExpr.setStringMetricPlanned("plannedLeoReconciliationDecision", decision);
		tupleExpr.setStringMetricPlanned("plannedLeoReconciliationReason", reason);
		if (Double.isFinite(rowRatio)) {
			tupleExpr.setDoubleMetricPlanned("plannedLeoRowsVsBaseRatio", rowRatio);
		}
		if (Double.isFinite(workRatio)) {
			tupleExpr.setDoubleMetricPlanned("plannedLeoWorkRowsVsBaseRatio", workRatio);
		}
		if (Double.isFinite(confidence)) {
			tupleExpr.setDoubleMetricPlanned("plannedLeoReconciliationConfidence", confidence);
		}
	}
}
